import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import "./login.css";

export default function Login() {
  const [isRegister, setIsRegister] = useState(false);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [confirm, setConfirm] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    if (isRegister && password !== confirm) {
      setError("Passwords do not match");
      setLoading(false);
      return;
    }

    const endpoint = isRegister ? "/api/auth/register" : "/api/auth/login";
    const payload = isRegister ? { email, password } : { email, password };

    try {
      const res = await axios.post(`http://localhost:5050${endpoint}`, payload);
      const { token, role, id } = res.data;

      // Store token + role-specific id (sno) – the same keys used everywhere else
      localStorage.setItem("token", token);
      localStorage.setItem("userId", id);
      localStorage.setItem("role", role);

      // Redirect to the correct dashboard
      if (role === "mentor") navigate("/mentor-dashboard");
      else if (role === "student") navigate("/student-dashboard");
      else navigate("/"); // fallback
    } catch (err) {
      setError(err.response?.data?.error || "Something went wrong");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-page">
      <div className="login-card">
        <h2>{isRegister ? "Activate Account" : "Login"}</h2>

        {error && <p className="error-msg">{error}</p>}

        <form onSubmit={handleSubmit}>
          <div className="input-group">
            <label>Institutional Email</label>
            <input
              type="email"
              placeholder="name@domain.edu"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              disabled={loading}
            />
          </div>

          <div className="input-group">
            <label>Password</label>
            <input
              type="password"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              disabled={loading}
            />
          </div>

          {isRegister && (
            <div className="input-group">
              <label>Confirm Password</label>
              <input
                type="password"
                placeholder="••••••••"
                value={confirm}
                onChange={(e) => setConfirm(e.target.value)}
                required
                disabled={loading}
              />
            </div>
          )}

          <button type="submit" className="login-btn" disabled={loading}>
            {loading ? "Please wait…" : isRegister ? "Activate" : "Login"}
          </button>
        </form>

        <p className="toggle-text">
          {isRegister ? (
            <>
              Already have a password?{" "}
              <span className="link" onClick={() => setIsRegister(false)}>
                Login here
              </span>
            </>
          ) : (
            <>
              First time?{" "}
              <span className="link" onClick={() => setIsRegister(true)}>
                Set a password
              </span>
            </>
          )}
        </p>
      </div>
    </div>
  );
}
